var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"중계소 상태는 어떤가?","JPN":"中継所の状態はどうだ？","ENG":"How's the relay station?","TWN":"基地台情況如何？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"안 좋습니다. 건물 안이 완전히 쑥대밭이 됐어요.","JPN":"良くありません。建物の中が完全に荒らされています。","ENG":"Not good. The inside of the building is completely in ruins.","TWN":"不太好，裡面根本就是一團混亂。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"느낌이 안 좋군. 침식체들이 할 만한 짓은 아니야.","JPN":"嫌な予感がするな。侵食体の仕業ではなさそうだ。","ENG":"I've got a bad feeling about this. This isn't something C.O.s would do.","TWN":"我有不好的預感，這不像是侵蝕體會做的事。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"하지만 이대로 두면 다른 주민들은 갱단한테 시달려도 도와달라고 할 방법이 없으니까요.","JPN":"でも、このままにしておくと住民たちがギャングにやられた時に助けを求める手段がなくなります。","ENG":"But if we don't fix it, the community will have no way of reaching out for help when the gangs harass them.","TWN":"但是不修的話，居民被幫派找麻煩時，會沒有求救的管道。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 주위에 수상한 움직임은 없는지 경계하고 있도록.","JPN":"そうだな。周りに怪しい動きはないか警戒してくれ。","ENG":"I know. Just keep an eye out for anything suspicious.","TWN":"也是，要注意一下周圍有沒有可疑的行動。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"두목이 부상을 입고 도망쳤다고 해도, 예언회가 완전히 와해된 건 아냐.","JPN":"ボスが負傷して逃げたとしても、預言会が完全に解散したわけではない。","ENG":"Their boss may be away licking his wounds, but that doesn't mean the MPS has been completely destroyed.","TWN":"雖然領頭的負傷逃跑，但預言會並沒有完全瓦解。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"트렁크에 있는 공구 챙겨서 따라와, 호라이즌.","JPN":"トランクにある工具を持ってついて来てくれ、ホライズン。","ENG":"Grab the tools from the trunk and follow me, Horizon.","TWN":"地平線，把箱子裡的工具拿來。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……알겠습니다. 휴먼.","JPN":"……わかりました、ヒューマン。","ENG":"…Very well, human.","TWN":"……好的，人類"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"팔자에도 없는 기술자 노릇까지 하게 만드는군. 참 성가신 동네야.","JPN":"専門でもないエンジニアの仕事までさせられることになるとは。本当に手のかかる町だ。","ENG":"Hmph, I can't believe they got me playing cable guy over here. What a lousy neighborhood.","TWN":"竟然還害我當起維修工，真是個麻煩的地方。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그렇게 생각하지 않나, 호라이즌?","JPN":"そう思わないか、ホライズン？","ENG":"Wouldn't you agree, Horizon?","TWN":"地平線，你不覺得嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"레이첼이 당신의 번식 욕구를 자극하는 행동을 했습니까.","JPN":"レイチェルがあなたの繁殖欲求を刺激するような行動をしましたか？","ENG":"Has Rachel stimulated your impulse for propagation?","TWN":"瑞秋有做什麼刺激你繁殖慾望的行為嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"조카뻘인 여자애한테 치근덕거리는 취미는 없어. 헛소리 말고 거기 드라이버나 집어 줘.","JPN":"姪っ子に当たる歳の女の子に手を出す趣味はない。くだらない質問はやめて、そこのドライバーでも渡してくれ。","ENG":"Don't be gross. She's young enough to be my niece. Shut up and just grab me that screwdriver.","TWN":"瑞秋就跟我的姪女一樣，我沒有戀童癖好嗎。少胡說八道，把螺絲起子拿給我。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"여기 있습니다. 그럼 어째서 그녀의 불합리한 요구를 받아들인 겁니까?","JPN":"はい、どうぞ。ならばどうして彼女の不合理な要求を受け入れたのですか？","ENG":"Here it is. Then why did you agree to her unreasonable request?","TWN":"給你。那你爲什麼要接受她不合理的要求？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"네가 눈에 밟혔다고 하면 되나?","JPN":"あんたのことが目に浮かんだというか、まあそんな感じだ。","ENG":"I guess you got my attention.","TWN":"是因為你的關係，這樣可以嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"딱히 당신 시선을 끌 목적은 없습니다만.","JPN":"別にあなたの目を引くような行動をした覚えはありませんが。","ENG":"But I have no reason to attract your attention.","TWN":"我沒有想要吸引你目光的意思。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"남들 관심 받기 싫었으면 애초에 그렇게 온몸으로 나 좀 챙겨 달라고 하지 말았어야지.","JPN":"人の目を引きたくなければ、かまってほしいと思われるような行動をしなければいいだろ？","ENG":"If you really wanted folks to leave you alone, you shouldn't have made it so obvious that you wanted attention.","TWN":"如果不希望別人關心你，那一開始就不要表現得一副很需要人家照顧的樣子。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이해할 수 없는 관점이군요. 저는 정서적인 공감대를 요구한 적 없습니다.","JPN":"理解できない観点ですね。情緒的共感を求めた覚えはありませんが。","ENG":"That does not compute. I've never demanded emotional sympathy from anyone.","TWN":"我無法理解，我從來沒有要求過情感上的交流。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};